/* SQL ID : ReshDAO.listMyCreCrsReshPaging 설 명 : 내 강의에 등록된 설문 리스트 조회 페이징 */
SELECT ROW_NUMBER() OVER(ORDER BY D.SBJCTNM, D.DVCLAS_NO, C.FRST_INQ_DTTM DESC) AS lineNo , C.SRVY_ID AS reschCd , C.SRVY_TTL AS reschTitle , D.SBJCT_ID AS creYear , D.CRS_ID AS creTerm , D.SBJCTNM AS crsCreNm , D.DVCLAS_NO AS declsNo , F.SMSTRNM AS termNm , COUNT(1) OVER() AS totalCnt FROM SBJCT_PROF A JOIN TB_LMS_RESCH_CRE_CRS_RLTN B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' JOIN TB_LMS_SRVY C ON C.SRVY_ID = B.SRVY_ID AND C.ORG_ID = #{orgId} AND C.DELYN = 'N' JOIN TB_LMS_SBJCT D ON D.SBJCT_ID = A.SBJCT_ID LEFT JOIN TB_LMS_TERM_CRE_CRS_RLTN E ON E.SBJCT_ID = D.SBJCT_ID LEFT JOIN CRS_SMSTR F ON F.CRS_SMSTR_ID = E.CRS_SMSTR_ID WHERE A.USER_ID = #{rgtrId}
AND D.SBJCT_ID = #{crsCreCd}
AND F.CRS_SMSTR_ID = #{termCd}
AND D.SBJCT_ID = #{creYear}
AND D.CRS_ID = #{creTerm}
AND LOWER(C.SRVY_TTL) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))

mapper.insert:
		/*
             SQL ID : ReshDAO.insertResh
             	설  명 : 설문 등록 
        */
		INSERT INTO TB_LMS_SRVY (
			  SRVY_ID
			, SRVY_CTGRCD
			, SRVY_TMPLT_CD
			, SRVY_TMPLTYN
			, ORG_ID
			, SRVY_TTL
			, SRVY_CTS
			, SRVY_TYCD
			, JOIN_TRGT
			, SRVY_SDTTM
			, RESCH_END_DTTM
			, RSLT_OPEN_TYCD
			, MRK_INQYN
			, DVCLAS_REGYN
			, QSTN_COPYYN
			, ITEM_COPY_RESCH_CD
			, MRK_RFLTYN
			, MRK_OYN
			, EXTD_PTCPYN
			, EXTD_EDTTM
			, EVL_CTGRCD
			, USEYN
			, DELYN
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
		)
		VALUES (
			  #{reschCd}
			, #{reschCtgrCd}
			, #{reschTplCd}
			, #{reschTplYn}
			, #{orgId}
			, #{reschTitle}
			, #{reschCts}
			, #{reschTypeCd}
			, #{joinTrgt}
			, #{reschStartDttm}
			, #{reschEndDttm}
			, #{rsltTypeCd}
			, #{scoreViewYn}
			, #{declsRegYn}
			, #{itemCopyYn}
			, CASE WHEN #{itemCopyYn} = 'Y' THEN #{itemCopyReschCd} ELSE NULL END
			, #{scoreAplyYn}
			, #{scoreOpenYn}
			, #{extJoinYn}
			, #{extEndDttm}
			, #{evalCtgr}
			, #{useYn}
			, #{delYn}
			, #{rgtrId}
			, FN_DTTM()
			, #{mdfrId}
			, FN_DTTM()
		)

/* SQL ID : ReshDAO.copyResh 설 명 : 설문 복사 */ INSERT INTO TB_LMS_SRVY ( SRVY_ID , SRVY_CTGRCD , SRVY_TMPLT_CD , SRVY_TMPLTYN , ORG_ID , SRVY_TTL , SRVY_CTS , SRVY_TYCD , JOIN_TRGT , SRVY_SDTTM , RESCH_END_DTTM , RSLT_OPEN_TYCD , MRK_INQYN , DVCLAS_REGYN , QSTN_COPYYN , ITEM_COPY_RESCH_CD , USEYN , DELYN , SRVY_QSTNS_CMPTNYN , MRK_RFLTYN , MRK_RFLTRT , MRK_OYN , EXTD_PTCPYN , EXTD_EDTTM , EVL_CTGRCD , RGTR_ID , FRST_INQ_DTTM ) SELECT #{reschCd} , SRVY_CTGRCD , SRVY_TMPLT_CD , SRVY_TMPLTYN , ORG_ID , SRVY_TTL , SRVY_CTS , SRVY_TYCD , JOIN_TRGT , SRVY_SDTTM , RESCH_END_DTTM , RSLT_OPEN_TYCD , MRK_INQYN , 'N' , QSTN_COPYYN , ITEM_COPY_RESCH_CD , USEYN , DELYN , SRVY_QSTNS_CMPTNYN , MRK_RFLTYN , MRK_RFLTRT , MRK_OYN , EXTD_PTCPYN , EXTD_EDTTM , EVL_CTGRCD , #{rgtrId}
, TO_CHAR(SYSDATE + NUMTODSINTERVAL(#{lineNo}, 'SECOND'), 'YYYYMMDDHH24MISS')
, FN_DTTM()
FROM TB_LMS_SRVY WHERE SRVY_ID = #{copyReschCd}

/*
     SQL ID : ReshDAO.insertReshCreCrsRltn
     	설  명 : 설문 강의 연결 등록 
*/
INSERT INTO TB_LMS_RESCH_CRE_CRS_RLTN (
       SBJCT_ID
     , SRVY_ID
     , GRPCD
     , DELYN
) VALUES (
       #{crsCreCd}
     , #{reschCd}
     , #{grpCd}
     , 'N'
)

mapper.update:
		/*
             SQL ID : ReshDAO.updateResh
             	설  명 : 설문 수정 
        */
		UPDATE TB_LMS_SRVY SET
			  MDFR_ID 			 = #{mdfrId}
			, MOD_DTTM 			 = FN_DTTM()
			, SRVY_TTL 		 = #{reschTitle}
			, SRVY_CTS 		 = #{reschCts}
			, JOIN_TRGT 		 = #{joinTrgt}
			, SRVY_SDTTM 	 = #{reschStartDttm}
			, RESCH_END_DTTM 	 = #{reschEndDttm}
			, RSLT_OPEN_TYCD 		 = #{rsltTypeCd}
			, MRK_INQYN 	 = #{scoreViewYn}
			, DVCLAS_REGYN 		 = #{declsRegYn}
			, QSTN_COPYYN 		 = #{itemCopyYn}

			, ITEM_COPY_RESCH_CD = #{itemCopyReschCd}

			, MRK_RFLTYN		 = #{scoreAplyYn}
			, MRK_OYN		 = #{scoreOpenYn}
			, EXTD_PTCPYN		 = #{extJoinYn}
			, EXTD_EDTTM		 = #{extEndDttm}
			, EVL_CTGRCD			 = #{evalCtgr}
			, USEYN = #{useYn}
		WHERE SRVY_ID = #{reschCd}

/*
     SQL ID : ReshDAO.updateReshQstnCopy
    	 설  명 : 설문 문항가져오기 시 복사된 설문 정보 업데이트
*/
UPDATE TB_LMS_SRVY SET
       MDFR_ID 				= #{mdfrId}
     , MOD_DTTM 			= FN_DTTM()
     , QSTN_COPYYN 		= #{itemCopyYn}
     , ITEM_COPY_RESCH_CD 	= #{itemCopyReschCd}
 WHERE SRVY_ID = #{reschCd}

/*
     SQL ID : ReshDAO.updateReshDelYn
     	설  명 : 설문 삭제 상태로 수정
*/
UPDATE TB_LMS_SRVY SET
      MDFR_ID   = #{mdfrId}
    , MOD_DTTM = FN_DTTM()
    , DELYN   = 'Y'
 WHERE SRVY_ID = #{reschCd}

mapper.select:
/*
     SQL ID : ReshDAO.selectReshCreCrsDecls
     	설  명 : 설문과 같이 등록된 분반 또는 다른 과목 조회
 */
SELECT A.SRVY_ID 	AS reschCd
     , A.DELYN 	AS delYn
  FROM TB_LMS_RESCH_CRE_CRS_RLTN A
 WHERE A.SBJCT_ID = #{crsCreCd}
   AND A.GRPCD = #{declsGrpCd}

mapper.update:
	/*
         SQL ID : ReshDAO.updateReschSubmitYn
         	설  명 : 설문 문항 출제 완료 처리
     */
	UPDATE TB_LMS_SRVY SET
		  MDFR_ID = #{mdfrId}
		, MOD_DTTM = FN_DTTM()
		, SRVY_QSTNS_CMPTNYN = #{reschSubmitYn}
	 WHERE SRVY_ID = #{reschCd}

		/*
             SQL ID : ReshDAO.updateScoreOpenYn
             	설  명 : 설문 성적공개여부 수정 
        */
		UPDATE TB_LMS_SRVY SET
			  MDFR_ID			= #{mdfrId}
			, MOD_DTTM			= FN_DTTM()
			, MRK_OYN		= CASE WHEN #{scoreOpenYn} = 'Y' THEN 'Y' ELSE 'N' END
		WHERE SRVY_ID = #{reschCd}

		/*
             SQL ID : ReshDAO.updateScoreRatio
             	설  명 : 설문 성적 반영비율 수정
        */
        UPDATE TB_LMS_SRVY SET
			  MDFR_ID		= #{mdfrId}
			, MOD_DTTM		= FN_DTTM()
			, MRK_RFLTRT	= #{scoreRatio}
		WHERE SRVY_ID = #{reschCd}
